const amqp = require('amqplib');
const { validatePayment } = require('./paymentValidator'); // Assume this is a module for validating payment data
const { processPayment } = require('./paymentProcessor'); // Assume this is a module for processing payments
const { logError, logInfo } = require('./logger'); // Assume this is a logging module

const QUEUE_NAME = 'payment_events';
const RABBITMQ_URL = 'amqp://localhost'; // Replace with your RabbitMQ URL

async function startConsumer() {
    try {
        const connection = await amqp.connect(RABBITMQ_URL);
        const channel = await connection.createChannel();
        await channel.assertQueue(QUEUE_NAME, { durable: true });

        console.log(`Waiting for messages in ${QUEUE_NAME}...`);

        channel.consume(QUEUE_NAME, async (msg) => {
            if (msg !== null) {
                const paymentData = JSON.parse(msg.content.toString());

                try {
                    // Validate payment data
                    if (validatePayment(paymentData)) {
                        await processPayment(paymentData);
                        channel.ack(msg);
                        logInfo(`Processed payment: ${JSON.stringify(paymentData)}`);
                    } else {
                        logError(`Invalid payment data: ${JSON.stringify(paymentData)}`);
                        channel.nack(msg, false, false); // Do not requeue
                    }
                } catch (error) {
                    logError(`Error processing payment: ${error.message}`);
                    channel.nack(msg, false, false); // Do not requeue
                }
            }
        }, { noAck: false });
    } catch (error) {
        logError(`Failed to connect to RabbitMQ: ${error.message}`);
    }
}

startConsumer();